var e=JSON.parse(`[{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"같은 시간","JPN":"同時刻","ENG":"Meanwhile","TWN":"同一時間"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"subtitle","speaker":null,"text":{"KOREA":"관리국 직할 도시 <color=#ffd34c>샤레이드</color> 외곽 구역\\n<color=#ffd34c>프리드웬 기관</color> 비밀 격리 시설 LAKE-13","JPN":"管理局直轄都市<color=#ffd34c>シャレード</color>外郭地域\\n<color=#ffd34c>プリドウェン機関</color>秘密隔離施設LAKE-13","ENG":"Administration Direct Control City, <color=#ffd34c>Charade</color> Outskirts\\n<color=#ffd34c>Prydwen Institution</color> Secret Quarantine Facility LAKE-13","TWN":"管理局直轄都市<color=#ffd34c>查雷德</color>外郭區域\\n<color=#ffd34c>普利多溫機關</color>祕密隔離設施LAKE-13"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"제가 좀 늦었군요, 버넷.","JPN":"お待たせしましたわ、バーネット。","ENG":"I seem to have run a bit late, Burnett.","TWN":"我來晚了，伯內特。"},"stage":{"bg":"FACILITY","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L7_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"그래서 그녀의 상태는 어떻죠?","JPN":"それで、彼女の様子は？","ENG":"So, how is her condition?","TWN":"所以，她的狀態如何？"},"stage":{"bg":"FACILITY","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ROI_PRYDWEN_GALAHAD_NULL","text":{"KOREA":"보고한대로. 폭주하기 직전의 파편을 봉인하는 데는 성공했어.","JPN":"報告した通りだ。なんとか暴走する直前に破片を封印できた。","ENG":"As reported. We managed to seal the Fragment just before it had an outburst.","TWN":"跟報告一樣，已經成功封印即將暴走的碎片。"},"stage":{"bg":"FACILITY","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"ROI_PRYDWEN_GALAHAD_NULL","text":{"KOREA":"리오나는 아직 의식을 되찾지 못했지만…….","JPN":"リオナはまだ意識が戻ってないが……","ENG":"Liona still hasn't regained consciousness...","TWN":"雖然萊歐娜還沒有恢復意識……"},"stage":{"bg":"FACILITY","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"아니요, 현 시점에서 그녀가 의식을 되찾으면 우리야 말로 곤란해요.","JPN":"いいえ、現時点で彼女が意識を取り戻したら困ります。","ENG":"No. At this point, it would be worse if she did wake up.","TWN":"不，要是她在這個時間點醒來，反而會讓我們為難。"},"stage":{"bg":"FACILITY","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"<color=#ffd34c>그녀</color>가 정말로 <color=#ffd34c>그녀</color>인지 확신할 수 없으니까요.","JPN":"<color=#ffd34c>彼女</color>が本当に<color=#ffd34c>彼女</color>なのか、確信できませんから。","ENG":"Because we can't be certain that <color=#ffd34c>she</color> is truly <color=#ffd34c>her</color>.","TWN":"因為無法確定<color=#ffd34c>她</color>究竟是不是<color=#ffd34c>她</color>。"},"stage":{"bg":"FACILITY","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"그게 무슨 소리야? ","JPN":"どういう意味？ ","ENG":"What do you mean by that?","TWN":"那是什麼意思？ "},"stage":{"bg":"FACILITY","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L16_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"리온이 리온이 아닐 수도 있다고? 토토가 리온의 몸을 빼앗았다는 거야?","JPN":"リオンが、リオンじゃないかもしれない……？　トトがリオンの体を乗っ取ったってこと？","ENG":"Are you saying Liona might not be Liona anymore? That Toto took over her body?","TWN":"你是說萊恩可能已經不是萊恩了？托托奪走了萊恩的身體嗎？"},"stage":{"bg":"FACILITY","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"그럴 리가 없잖아……!","JPN":"そんなわけないよ……！","ENG":"That can't be true...!","TWN":"怎麼可能……！"},"stage":{"bg":"FACILITY","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"생긴 게 좀 괴상하기는 해도, 토토는 리온의 둘도 없는 친구야……!","JPN":"見た目はちょっと変でも、トトはリオンのかけがえない友達なんだ……！","ENG":"Even if he looks strange, Toto is Liona's one and only friend...!","TWN":"就算長得有點怪，托托是萊恩獨一無二的朋友……！"},"stage":{"bg":"OZ_01","bgm":"THEMA_PRYDWEN","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"그리고 우리의 친구이기도 해.","JPN":"それに……私たちの友達でもある。","ENG":"And our friend too.","TWN":"而且也是我們的朋友。"},"stage":{"bg":"OZ_01","bgm":"THEMA_PRYDWEN","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"그런데 친구가 친구의 몸을 뺏는다고? 내가 그 말을 믿을 것 같아……?","JPN":"なのに、友達が友達の体を奪う？　そんな話信じられるわけないだろ……","ENG":"So you're saying a friend would steal another friend's body? Do you really expect me to believe that...?","TWN":"朋友會奪走朋友的身體？你覺得我會相信這種話嗎……？"},"stage":{"bg":"FACILITY","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PUPPET_OZ_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L26_1","type":"dialog","speaker":"PUPPET_OZ_NULL_NULL","text":{"KOREA":"도로시…….","JPN":"ドロシー……","ENG":"Dorothy...","TWN":"桃樂絲……"},"stage":{"bg":"FACILITY","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PUPPET_OZ_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L28_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"당신들, 프리드웬 맞지?","JPN":"あんたたち、プリドウェンだよな。","ENG":"You're Prydwen, right?","TWN":"你們是普利多溫對吧？"},"stage":{"bg":"FACILITY","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"리온이 샤레이드에 찾아온 이유는 당신들을 찾기 위해서였어.","JPN":"リオンがシャレードに来たのは、あんたたちを探すためだった。","ENG":"Liona came to Charade to find you.","TWN":"萊恩會來到查雷德，就是為了找你們。"},"stage":{"bg":"FACILITY","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"프리드웬에서 <color=#ffd34c>초대장</color>을 보냈다면서 말이야.","JPN":"プリドウェンから<color=#ffd34c>招待状</color>が送られてきたって言って。","ENG":"She said Prydwen sent an <color=#ffd34c>invitation</color>.","TWN":"她說普利多溫寄出了<color=#ffd34c>邀請函</color>。"},"stage":{"bg":"FACILITY","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"설마 당신들은 처음부터 이렇게 될 줄 알고 있었던 거야?","JPN":"まさかあんたたち、最初からこうなるって知ってたのか？","ENG":"Don't tell me you knew this would happen from the start?","TWN":"難道你們從一開始就知道會變成這樣嗎？"},"stage":{"bg":"FACILITY","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"초대장이라고요?","JPN":"招待状？","ENG":"An invitation?","TWN":"邀請函？"},"stage":{"bg":"FACILITY","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"영문을 모르겠군요. 기관은 관리 대상에게 초대장 같은 걸 보내지 않습니다.","JPN":"訳がわかりませんね。機関が管理対象に招待状を送ることはありません。","ENG":"I'm afraid I have no idea what you mean. The Institution does not send invitations to those under special surveillance.","TWN":"我不太明白，機關並不會向管理對象寄送邀請函之類的東西。"},"stage":{"bg":"FACILITY","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"뭐? 관리 대상? 지금 말 다 했어?","JPN":"は？　管理対象？　言わせておけば！","ENG":"What? Special surveillance? Are you even hearing yourself?","TWN":"什麼？管理對象？你說完了嗎？"},"stage":{"bg":"FACILITY","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L38_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"다 못했습니다. 애초에 그녀가 갑자기 사라져서 곤란한 건……","JPN":"まだあります。そもそも彼女が突然姿を消して迷惑しているのは……","ENG":"I'm not finished. In the first place, the real problem was that she suddenly disappeared–","TWN":"還沒呢。一開始她突然消失，讓我們也很困擾……"},"stage":{"bg":"FACILITY","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"흐읍!","JPN":"ふっ！","ENG":"Hmph!","TWN":"唔！"},"stage":{"bg":"FACILITY","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L42_1","type":"dialog","speaker":"ROI_PRYDWEN_GALAHAD_NULL","text":{"KOREA":"기관장, 여기선 나한테 맡겨.","JPN":"機関長、ここは任せてくれ。","ENG":"Chief, leave this to me.","TWN":"機關長，這裡交給我吧。"},"stage":{"bg":"FACILITY","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L43_1","type":"dialog","speaker":"ROI_PRYDWEN_GALAHAD_NULL","text":{"KOREA":"내가 설명할 테니까.","JPN":"俺が説明する。","ENG":"I'll explain.","TWN":"我來說明。"},"stage":{"bg":"FACILITY","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"……물벼룩 주제에 손버릇이 고약해졌군요.","JPN":"……ミジンコのくせに、手癖が悪くなりましたわね。","ENG":"...You're getting awfully handsy, Water Flea.","TWN":"……區區水蚤，手腳倒是越來越不老實了。"},"stage":{"bg":"FACILITY","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"흥, 마음대로 하세요.","JPN":"ふん、好きにしなさい。","ENG":"Hmph. Do as you please.","TWN":"哼，隨便你。"},"stage":{"bg":"FACILITY","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"C":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"ROI_PRYDWEN_GALAHAD_NULL","text":{"KOREA":"우선은 사과할게, 도로시 그리고 허수아.","JPN":"まず謝るよ。ドロシー、あとカカシ・コトリ。","ENG":"First, let me apologize, Dorothy. And you too, Skia Crow.","TWN":"首先我要跟你們道歉，桃樂絲，還有禾蘇亞。"},"stage":{"bg":"FACILITY","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L48_1","type":"dialog","speaker":"ROI_PRYDWEN_GALAHAD_NULL","text":{"KOREA":"우리 프리드웬 기관은 아주 오래전부터 너희와 네 친구를 감시하고 있었어.","JPN":"俺たちプリドウェン機関はかなり前からお前たちを監視していた。","ENG":"The Prydwen Institution has been monitoring you and your friends for a very long time.","TWN":"我們普利多溫機關從很久以前就一直在監視你們，還有你們的朋友。"},"stage":{"bg":"FACILITY","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"ROI_PRYDWEN_GALAHAD_NULL","text":{"KOREA":"그리고 너희가 신성 파편의 폭주로 인해, 끔찍한 사고를 당했다는 것도 이미 알고 있고.","JPN":"数年前にあった、神聖の破片が暴走した事件のせいでお前たちが酷い目に遭ったことも知っている。","ENG":"And we already knew that you were caught in a horrific accident caused by a rampaging Divinity Fragment.","TWN":"而且我們也早就知道你們因為神聖碎片暴走，遭遇那場可怕意外的事了。"},"stage":{"bg":"FACILITY","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"신성 파편이라고……?","JPN":"神聖の破片……？","ENG":"Divinity Fragment...?","TWN":"神聖碎片……？"},"stage":{"bg":"FACILITY","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"PUPPET_OZ_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L4_1","type":"dialog","speaker":"ROI_PRYDWEN_GALAHAD_NULL","text":{"KOREA":"저길 봐.","JPN":"あれを見ろ。","ENG":"Look over there.","TWN":"你看那個。"},"stage":{"bg":"FACILITY","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"PUPPET_OZ_NULL_NULL","text":{"KOREA":"저건……?","JPN":"あれは……？","ENG":"That's...?","TWN":"那是……？"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"PUPPET_OZ_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"PUPPET_OZ_NULL_NULL","text":{"KOREA":"토토의 생체 신호와 유사한 파장이야……!","JPN":"トトの生体信号に類似した波長……！","ENG":"It's a waveform similar to Toto's biometric signal...!","TWN":"和托托的身體訊號類似的碎片……！"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"PUPPET_OZ_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"저 거대한 게 토토랑 비슷하다고?","JPN":"あのどでかいやつがトトに似てるだって？","ENG":"That massive thing is similar to Toto?","TWN":"那麼，那個巨大的東西和托托很像嗎？"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PUPPET_OZ_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"그럼, 설마……?","JPN":"じゃあ、まさか……？","ENG":"Then don't tell me...","TWN":"那樣的話，難道……？"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PUPPET_OZ_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"ROI_PRYDWEN_GALAHAD_NULL","text":{"KOREA":"저것의 정체는 <color=#ffd34c>지식의 호수</color>…….","JPN":"あれの正体は<color=#ffd34c>知識の湖</color>……","ENG":"That entity is the <color=#ffd34c>Lake of Knowledge</color>.","TWN":"那個東西的真面目是<color=#ffd34c>知識湖水</color>……"},"stage":{"bg":"FACILITY","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_IDLE"},"R":{"char_id":"PUPPET_OZ_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"ROI_PRYDWEN_GALAHAD_NULL","text":{"KOREA":"거대한 파편 형태로 존재하는 신성 정보 집합체야.","JPN":"巨大な破片の形で存在している、神聖情報集合体だ。","ENG":"A Divinity collection of information existing in a massive fragmentary form.","TWN":"那是以巨大碎片形態存在的神性資訊集合體。"},"stage":{"bg":"FACILITY","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_IDLE"},"R":{"char_id":"PUPPET_OZ_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"ROI_PRYDWEN_GALAHAD_NULL","text":{"KOREA":"수년 전에 발생했던 사고에 휘말려, 네 친구는 저것과 이어져 버렸어.","JPN":"あの時の事故に巻き込まれ、お前の友達はあれと繋がってしまった。","ENG":"Your friend was caught in an accident years ago and became connected to it.","TWN":"你的朋友被捲入數年前發生的意外，並與那個連結在一起。"},"stage":{"bg":"FACILITY","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ROI_PRYDWEN_GALAHAD_NULL","text":{"KOREA":"덕분에 너희는 목숨을 건졌지만, 리오나는 언제 터질지 모르는 시한폭탄이 되어버렸지.","JPN":"おかげでお前たちの命は助かったけど、リオナはいつ爆発してもおかしくない爆弾になっちまった。","ENG":"Thanks to that, you survived, but Liona became a ticking time bomb that could go off at any moment.","TWN":"因此你們保住了性命，但里歐娜卻成了不知何時會爆炸的定時炸彈。"},"stage":{"bg":"FACILITY","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"그 말은 리온이 토토의 입마개를 완전히 벗긴다는 게…….","JPN":"つまり、リオンがトトの口輪を完全に外すってことは……","ENG":"Then Liona removing Toto's muzzle means...","TWN":"那句話的意思是，里昂將會徹底解開托托的口罩……"},"stage":{"bg":"FACILITY","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"PUPPET_OZ_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L27_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"입마개를 벗긴다는 행위는 트리거겠죠.","JPN":"口輪を外す行為がトリガーだったのでしょう。","ENG":"Removing the muzzle would be the trigger.","TWN":"解開口罩這個行為，本身就是觸發器吧。"},"stage":{"bg":"FACILITY","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"이 도시를 지키기 위해, 리오나 하트는 자기 목숨을 지식의 호수에 바친 거예요.","JPN":"この都市を守るために、リオナ・ハートは自分の命を知識の湖に捧げたのです。","ENG":"To protect this city, Liona Hartt offered her own life to the Lake of Knowledge.","TWN":"為了守護這座城市，里歐娜．哈特將自己的生命獻給了知識湖水。"},"stage":{"bg":"FACILITY","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FACILITY","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"이 다리로 있는 힘껏 달려서, 미소 짓는 사람이 리온이라면 난 그것만으로도 충분해.","JPN":"この脚で精一杯走ってリオンが微笑んでくれるのなら、私はそれで十分。","ENG":"If I run with all my strength, and Liona is the one who ends up smiling, that's more than enough for me.","TWN":"如果用這雙腿拼命奔跑、露出笑容的人是萊恩，那我就滿足了。"},"stage":{"bg":"GAUNTLET","bgm":"THEMA_PRYDWEN","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"제길……!","JPN":"くそ……！","ENG":"Damn it...!","TWN":"可惡……！"},"stage":{"bg":"FACILITY","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L37_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"이런 걸 바란 건 아니었는데……!","JPN":"こんなことを望んだわけじゃない……！","ENG":"This isn't what I wanted...!","TWN":"我不希望事情變成這樣啊……！"},"stage":{"bg":"FACILITY","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"PUPPET_OZ_NULL_NULL","text":{"KOREA":"바이탈 체크 확인. 하지만 리온은 아직 살아있잖아?","JPN":"バイタルチェック確認。でもリオンはまだ生きているよ？","ENG":"Vital check confirmed. But Liona is still alive.","TWN":"確認生命徵象，不過萊恩不是還活著嗎？"},"stage":{"bg":"FACILITY","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PUPPET_OZ_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"PUPPET_OZ_NULL_NULL","text":{"KOREA":"위험한 존재가 되었을지도 모르는 리온을 살려둔 건, 다른 방법이 있다는 거야?","JPN":"危険な存在になったかもしれないリオンを生かしておくのは、他に方法があるってこと？","ENG":"If you left her alive even after she became a dangerous existence, that means there's another way?","TWN":"既然讓可能已經成為危險存在的萊恩活著，就代表還有其他方法吧？"},"stage":{"bg":"FACILITY","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PUPPET_OZ_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L44_1","type":"dialog","speaker":"ROI_PRYDWEN_GALAHAD_NULL","text":{"KOREA":"그래, 아직 포기하기는 일러.","JPN":"ああ、まだ諦めるには早い。","ENG":"That's right. It's too early to give up.","TWN":"是啊，現在放棄還太早了。"},"stage":{"bg":"FACILITY","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"ROI_PRYDWEN_GALAHAD_NULL","text":{"KOREA":"그날, 나는 다짐했으니까.","JPN":"あの日、俺は誓ったんだ。","ENG":"That day, I made a vow.","TWN":"因為那一天，我已經立下誓言。"},"stage":{"bg":"PRYDWEN_04","bgm":"THEMA_PRYDWEN","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L48_1","type":"dialog","speaker":"ROI_PRYDWEN_GALAHAD_NULL","text":{"KOREA":"그때와 같은 일을 절대로 되풀이하지 않겠다고.","JPN":"二度と同じ過ちを繰り返さないって。","ENG":"That I would never let the same thing happen again.","TWN":"絕對不會再讓同樣的事情重演。"},"stage":{"bg":"PRYDWEN_04","bgm":"THEMA_PRYDWEN","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L49_1","type":"dialog","speaker":"ROI_PRYDWEN_GALAHAD_NULL","text":{"KOREA":"다시는 누군가가 일방적으로 희생당하는 것을 지켜 보고만 있지는 않겠다고……!","JPN":"二度と、誰かが一方的に犠牲になるのを、ただ黙って見ているようなことはしないって……！","ENG":"That I would never again stand by and watch someone be sacrificed like that...!","TWN":"不會再只是眼睜睜看著某個人單方面犧牲……！"},"stage":{"bg":"PRYDWEN_04","bgm":"THEMA_PRYDWEN","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L50_1","type":"dialog","speaker":"ROI_PRYDWEN_GALAHAD_NULL","text":{"KOREA":"그러기 위해서 이 방패를 짊어졌어. 그리고…….","JPN":"そのために俺はこの盾を引き継いだ。そして……","ENG":"That's why I took up this shield. And...","TWN":"為了做到這一點，我才揹起這面盾。而且……"},"stage":{"bg":"PRYDWEN_04","bgm":"THEMA_PRYDWEN","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"ROI_PRYDWEN_GALAHAD_NULL","text":{"KOREA":"그러기 위해서라면, 얼마든지 적과도 손을 잡을 수 있지.","JPN":"そのためなら、敵とだっていくらでも手を組める。","ENG":"For that, I'll even gladly join hands with the enemy.","TWN":"如果是為了這一點，我也可以與敵人聯手。"},"stage":{"bg":"FACILITY","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"적과 손을 잡는다고……?","JPN":"敵と手を組む、って……？","ENG":"Join hands with the enemy...?","TWN":"與敵人聯手……？"},"stage":{"bg":"FACILITY","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"PUPPET_OZ_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L9_1","type":"dialog","speaker":"ROI_PRYDWEN_GALAHAD_NULL","text":{"KOREA":"그러니까 두 사람 모두 걱정하지 마.","JPN":"だから二人とも心配するな。","ENG":"So don't worry, either of you.","TWN":"所以你們兩個都不用擔心。"},"stage":{"bg":"FACILITY","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"ROI_PRYDWEN_GALAHAD_NULL","text":{"KOREA":"지금의 프리드웬은, 그리고 나는 절대로 네 친구를 외면하지 않을 테니까.","JPN":"今のプリドウェンは、そして俺は、決してお前の友達を見捨てたりしない。","ENG":"The current Prydwen, and I, will never abandon your friend.","TWN":"現在的普利多溫機關，還有我，絕對不會對你們的朋友視而不見。"},"stage":{"bg":"FACILITY","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_LAUGH"}}}},{"id":"L12_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"아가씨, 성궤에서 요청하신 아티팩트의 반출을 마쳤습니다.","JPN":"お嬢様。ご指示の通り、アーティファクトを聖櫃から搬出しました。","ENG":"Lady Elizabeth, we have completed the retrieval of the Artifact you requested from the Ark of the Covenant.","TWN":"小姐，已自聖軌中調出您要求的神器。"},"stage":{"bg":"FACILITY","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L13_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"<color=#ffd34c>요도</color>를 가지고 현실로 부상하도록 하죠.","JPN":"<color=#ffd34c>妖刀</color>を持って現実に浮上します。","ENG":"Let's bring the <color=#ffd34c>demonic blade</color> up into reality.","TWN":"帶著<color=#ffd34c>妖刀</color>，浮上現實吧。"},"stage":{"bg":"FACILITY","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"서둘러 주세요, 라이언.","JPN":"急いでください、ライアン。","ENG":"Please hurry, Ryan.","TWN":"請快一點，萊恩。"},"stage":{"bg":"FACILITY","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"오늘 밤은 무척 짧을 겁니다.","JPN":"今夜はとても短い夜になりますわ。","ENG":"Tonight will be very short.","TWN":"今夜會非常短暫。"},"stage":{"bg":"FACILITY","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"기관에서 준비할 수 있는 최고 의료 설비와 인력…….","JPN":"機関が用意できる最高の医療設備と人材……","ENG":"The best medical facilities and personnel the Institution can prepare...","TWN":"機關能準備的最高等級醫療設備與人力……"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"여러 사람의 손을 거치면서, 충분한 역사와 카르마가 쌓인 아티팩트…….","JPN":"様々な人の手を渡り、十分な歴史とカルマが蓄積されたアーティファクト……","ENG":"An Artifact with sufficient history and karma, having passed through many hands...","TWN":"經過無數人之手，累積充分歷史與業力的神器……"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"그리고 가용할 수 있는 가아그셰블라의 파편…….","JPN":"そして可用なガアグシェブラの破片……","ENG":"And the Fragment of Gha'agsheblah we can make use of...","TWN":"以及可動用的加格舍夫拉的碎片……"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"자, 이걸로 당신 말한 조건은 모두 갖추었어요.","JPN":"これであなたに言われた条件はすべて揃えましたわ。","ENG":"There. That fulfills all the conditions you mentioned.","TWN":"來，這樣一來你提出的條件都備齊了。"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L24_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"기관에서 이정도까지 편의를 봐주었으니, 반드시 성과를 보여야 할 겁니다.","JPN":"ここまで機関が便宜を図ったからには、必ず成果を出していただきますわ。","ENG":"The Institution has gone this far for you, so you'd better deliver results.","TWN":"機關都已經通融到這種程度了，你一定得拿出成果。"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"……아비게일 종교학부장.","JPN":"……アビゲイル宗教学部長。","ENG":"...Dean Abigail.","TWN":"……亞比該宗教學院院長。"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"물론이야. 기관장님.","JPN":"もちろんよ、機関長。","ENG":"Of course, Chief.","TWN":"當然了，機關長。"},"stage":{"bg":"FACILITY","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L28_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"하지만 이렇게까지 짧은 시간에 의식 준비를 마치다니…….","JPN":"でも、こんな短時間で儀式の準備を終えるだなんて……","ENG":"But to complete the ritual preparations in such a short time...","TWN":"不過能在這麼短的時間內完成儀式所有準備……"},"stage":{"bg":"FACILITY","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"설마, 도도한 기관장님께서 프라이드를 내려놓을 줄은 몰랐는데~?","JPN":"まさか、あの気位の高い機関長がプライドを手放すとは思わなかったわ～","ENG":"I never imagined the proud Chief would set aside her pride.","TWN":"我還真沒想到高傲的機關長居然會放下自尊呢～？"},"stage":{"bg":"FACILITY","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"착각하지 마세요, 종교학부장.","JPN":"勘違いしないでください、宗教学部長。","ENG":"Don't misunderstand, Dean of Religion.","TWN":"請別誤會，宗教學院院長。"},"stage":{"bg":"FACILITY","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L33_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"기관은 항상 목적을 이루기 위해서라면, 수단을 가리지 않았습니다.","JPN":"これまでも機関は目的のためなら手段を選びませんでしたわ。","ENG":"The Institution has never hesitated to use any means necessary to achieve its goals.","TWN":"機關一向都是不擇手段達成目的。"},"stage":{"bg":"FACILITY","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"그리고 지금은 그 수단이 당신일 뿐이죠.","JPN":"そして今は、その手段があなたであるだけの話です。","ENG":"And right now, you simply happen to be the means.","TWN":"只是現在那個手段正好是你而已。"},"stage":{"bg":"FACILITY","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L35_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"후훗, 그 쌀쌀맞은 표정이 매력적이라니깐?","JPN":"ふふっ、その冷たい表情が魅力的なのよね。","ENG":"Fufu, that icy expression is what makes you so charming.","TWN":"呵呵，那副冷淡的表情真迷人呢。"},"stage":{"bg":"FACILITY","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L37_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"수단이라…….","JPN":"手段か……","ENG":"A means, huh...","TWN":"手段啊……"},"stage":{"bg":"FACILITY","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"뭐, 좋아. 기관에 빚을 지어두는 것도 나쁘지는 않겠지.","JPN":"まあ、いいわ。機関に貸しを作っておくのも悪くないだろうし。","ENG":"Well, fine. Owing the Institution a favor isn't so bad.","TWN":"好吧，欠機關一個人情也不是壞事。"},"stage":{"bg":"FACILITY","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"무엇보다 현시점에서 내 목적과 가장 부합하는 건, 당신들일 테니까 말이야.","JPN":"何より現時点で、私の目的に一番合致するのはあなたたちだもの。","ENG":"More importantly, at this moment, you align best with my objectives.","TWN":"更何況現階段最符合我目的的，正是你們。"},"stage":{"bg":"FACILITY","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};